package io.dnlwjtud.blog.members.config.handler;

import io.dnlwjtud.blog.members.dto.MemberDetails;
import io.dnlwjtud.blog.members.dto.TokenResponse;
import io.dnlwjtud.blog.members.service.AuthService;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.user.OAuth2User;
import org.springframework.stereotype.Component;

@Component
public class AuthenticationSuccessHandlerImpl {

    private final AuthService authService;

    public void onAuthenticationSuccess(Authentication authentication, HttpServletResponse response) throws IOException {
        MemberDetails details = (MemberDetails) authentication.getPrincipal();
        TokenResponse tokens = authService.issueTokens(details.getUsername(), details.getRole().name());

        String accessToken = tokenProvider.issue(expiration, createClaims(authentication.getPrincipal()));

        response.addHeader("token", accessToken);
        response.setContentType("application/json;charset=UTF-8");
        response.getWriter().write("{\"accessToken\":\"" + tokens.accessToken() + "\",\"refreshToken\":\"" + tokens.refreshToken() + "\"}");
    }

    private Map<String, Object> createClaims(Object principal) {
        if (principal instanceof MemberDetails memberDetails) {
            return Map.of("username", memberDetails.getUsername(), "role", memberDetails.getRole().name());
        } else if (principal instanceof OAuth2User oauth2User) {
            return Map.of("username", oauth2User.getAttribute("username"), "role", oauth2User.getAttribute("role"));
        }
        throw new IllegalArgumentException("Unsupported principal type: " + principal.getClass().getName());
    }

}
